import React, { useEffect, useState } from 'react';
import { business } from '../services/api';
import { Link } from 'react-router-dom';

export default function Dashboard() {
  const [businesses, setBusinesses] = useState([]);
  const [form, setForm] = useState({ businessName: '', businessType: '', reviewDestination: '', description: '', experienceTags: '' });

  useEffect(() => {
    loadBusinesses();
  }, []);

  const loadBusinesses = async () => {
    const res = await business.getAll();
    setBusinesses(res.data);
  };

  const createBusiness = async (e) => {
    e.preventDefault();
    const tags = form.experienceTags.split(',').map(s => s.trim());
    await business.create({ ...form, experienceTags: tags });
    setForm({ businessName: '', businessType: '', reviewDestination: '', description: '', experienceTags: '' });
    loadBusinesses();
  };

  return (
    <div className="p-8 max-w-4xl mx-auto">
      <h1 className="text-3xl font-bold mb-6">Dashboard</h1>
      <form onSubmit={createBusiness} className="mb-8 space-y-4">
        <input className="w-full p-2 border rounded" placeholder="Business Name" value={form.businessName} onChange={(e) => setForm({...form, businessName: e.target.value})} />
        <input className="w-full p-2 border rounded" placeholder="Business Type" value={form.businessType} onChange={(e) => setForm({...form, businessType: e.target.value})} />
        <input className="w-full p-2 border rounded" placeholder="Review Destination URL" value={form.reviewDestination} onChange={(e) => setForm({...form, reviewDestination: e.target.value})} />
        <input className="w-full p-2 border rounded" placeholder="Description" value={form.description} onChange={(e) => setForm({...form, description: e.target.value})} />
        <input className="w-full p-2 border rounded" placeholder="Experience Tags (comma separated)" value={form.experienceTags} onChange={(e) => setForm({...form, experienceTags: e.target.value})} />
        <button type="submit" className="bg-green-500 text-white py-2 px-4 rounded">Create Business</button>
      </form>
      <div className="grid gap-4">
        {businesses.map(b => (
          <div key={b._id} className="border p-4 rounded shadow">
            <h2 className="text-xl font-semibold">{b.businessName}</h2>
            <p className="text-gray-600">{b.businessType}</p>
            <div className="mt-2 space-x-2">
              <Link to={`/branches/${b._id}`} className="bg-blue-500 text-white px-3 py-1 rounded">Branches</Link>
              <Link to={`/analytics/${b._id}`} className="bg-purple-500 text-white px-3 py-1 rounded">Analytics</Link>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
